#include <stdio.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    for(int tc=0; tc<T; ++tc){
        int arr[4] = {1,2,3,4};
        int *ptr = arr;
        for(int i=0;i<4;++i){
            printf("%d", *ptr);
            if(i<3) printf(" ");
            ++ptr;
        }
        if(tc != T-1) printf("\\n");
    }
    return 0;
}

